const usersRaw = $('GET Users Lookup').all().map(i => i.json);
const users = usersRaw.length === 1 && Array.isArray(usersRaw[0]) ? usersRaw[0] : usersRaw;

const userMap = {};
users.forEach(u => { if (u.close_user_id) userMap[u.close_user_id] = u.id; });

const triggerData = $('Start').first().json;
const since = triggerData.since || new Date().toISOString();
const until = triggerData.until || new Date().toISOString();
const currentDate = since.split('T')[0];
const endDate = until.split('T')[0];

return [{ json: { userMap, cursor: '', totalSynced: 0, currentDate, endDate, pageCount: 0 } }];

const data = $input.first().json;
const queries = [
  { type: 'object_type', object_type: 'activity.call' },
  {
    type: 'field_condition',
    field: { type: 'regular_field', object_type: 'activity.call', field_name: 'date_created' },
    condition: {
      type: 'moment_range',
      on_or_after: { type: 'fixed_local_date', value: data.currentDate, which: 'start' },
      before: { type: 'fixed_local_date', value: data.currentDate, which: 'end' }
    }
  }
];

const body = {
  query: { type: 'and', queries },
  sort: [{ direction: 'asc', field: { object_type: 'activity.call', type: 'regular_field', field_name: 'date_created' } }],
  _fields: { 'activity.call': ['id', 'lead_id', 'user_id', 'date_created', 'date_updated', 'duration', 'direction', 'disposition', 'phone', 'note', 'recording_url'] },
  _limit: 200
};
if (data.cursor) body.cursor = data.cursor;
return [{ json: { requestBody: JSON.stringify(body) } }];

const response = $input.first().json;
const calls = response.data || [];
const { userMap } = $('Build Lookups').first().json;

if (calls.length === 0) return [{ json: { _empty: true } }];

return calls.map(call => ({
  json: {
    close_call_id: call.id,
    user_id: userMap[call.user_id] || null,
    close_lead_id: call.lead_id || null,
    direction: call.direction || null,
    disposition: call.disposition || null,
    duration: call.duration != null ? call.duration : null,
    phone_number: call.phone || null,
    note: call.note || null,
    recording_url: call.recording_url || null,
    close_created_at: call.date_created || null,
    synced_at: new Date().toISOString()
  }
}));

const all = $input.all().map(i => i.json).filter(i => !i._empty);
const nullUserIds = all.filter(r => r.user_id === null).length;
return [{ json: { batch: all, count: all.length, nullUserIds } }];

const response = $('Search Close Calls').first().json;
const items = response.data || [];
const cursor = response.cursor || null;

const prev = $('Check More Pages').isExecuted
  ? $('Check More Pages').last().json
  : $('Build Lookups').first().json;

const batchCount = $('Aggregate Batch').first().json.count;
const cursorValid = cursor !== null && cursor !== undefined && cursor !== '';

// Noch mehr Daten für DIESEN Tag?
if (cursorValid && items.length > 0) {
  return [{ json: {
    currentDate: prev.currentDate,
    endDate: prev.endDate,
    cursor: cursor,
    totalSynced: prev.totalSynced + batchCount,
    pageCount: (prev.pageCount || 0) + 1,
    hasMore: true
  } }];
}

// Tag fertig → nächster Tag
const next = new Date(prev.currentDate + 'T00:00:00Z');
next.setUTCDate(next.getUTCDate() + 1);
const nextDate = next.toISOString().split('T')[0];
const hasMore = nextDate <= prev.endDate;

return [{ json: {
  currentDate: nextDate,
  endDate: prev.endDate,
  cursor: '',
  totalSynced: prev.totalSynced + batchCount,
  pageCount: 0,
  hasMore
} }];

const check = $('Check More Pages').last().json;
const totalSynced = check.totalSynced;
const syncRunId = $('Sync Start').first().json.id;
const nullUsers = check.totalNullUserIds || 0;
let warning = '';
if (nullUsers > 0) {
  warning = 'FK Warning: ' + nullUsers + '/' + totalSynced + ' null user_ids';
}
return [{ json: { count: totalSynced, syncRunId, warning } }];
